#!/bin/bash

set -e

echo "=============================================="
echo "      Playwright API Automation Execution"
echo "=============================================="

echo "Environment    : $ENV"
echo "Suite          : $SUITE"
echo "=============================================="

COMMAND="npx playwright test --project=api"

#########################################################
# Suite
#########################################################

if [ "$SUITE" != "all" ]; then
  COMMAND="$COMMAND --grep @$SUITE"
fi

#########################################################
# Display Command
#########################################################

echo ""
echo "Executing Command:"
echo "$COMMAND"
echo ""

#########################################################
# Execute Tests
#########################################################

eval "$COMMAND"

#########################################################
# Execution Completed
#########################################################

echo ""
echo "=============================================="
echo " API Automation Execution Completed Successfully "
echo "=============================================="
